using System.Drawing;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip default RenderMode changed.
        // Explicitly set to ManagerRenderMode to preserve .NET 8 visual behavior.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        Controls.Add(_statusStrip);
    }

    /// <summary>
    /// Demonstrates safe usage of IWindowsFormsEditorService.DropDownControl.
    /// In .NET 9, passing null throws ArgumentNullException.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (editorService is null)
            return;

        // .NET 9 breaking change: DropDownControl no longer accepts null.
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

